export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(keyOf));
  const candidates = new Map<string, Cell>();
  const neighborCounts = new Map<string, number>();

  for (const cell of liveCells.flatMap(neighborsOf)) {
    const k = keyOf(cell);
    candidates.set(k, cell);
    neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
  }

  return [...candidates].filter(([k]) =>
    survives(liveKeys.has(k), neighborCounts.get(k) ?? 0)
  ).map(([, cell]) => cell);
};

